#include <torch/extension.h>
#include <hip/hip_runtime.h>
#include <hip/hip_bf16.h>

// Declare the kernels from pa.cpp
__global__ void pa(
            __bf16* query,          // [B, HQ, S]
            __bf16* key_cache,      // [BLOCK, BLOCK_SIZE, HK, S]
            __bf16* value_cache,
            uint* kv_indptr,        // [B + 1]
            uint* kv_page_indices,  // [B * KV_LEN + 1]
            __bf16* out_seg,        // [B, HQ, PART, S]
            float* qk_ptr,          // [B, HK, HQ // HK, PART * KV_PART_SIZE]
            float* max_out,         // [B, HQ, PART, 1]
            float* sum_out);

__global__ void pa_reduce(
            uint* kv_indptr,        // [B + 1]
            __bf16* out_seg,        // [B, HQ, PART, S]
            float* max_out,         // [B, HQ, PART, 1]
            float* sum_out,         // [B, HQ, PART, 1]
            __bf16* out,            // [B, HQ, S]
            uint max_part);

void launch_pa(
    torch::Tensor query,
    torch::Tensor key_cache,
    torch::Tensor value_cache,
    torch::Tensor kv_indptr,
    torch::Tensor kv_page_indices,
    torch::Tensor out_seg,
    torch::Tensor qk_ptr,
    torch::Tensor max_out,
    torch::Tensor sum_out,
    int S,
    int KV_PART_SIZE
) {
    int B = query.size(0);
    int HQ = query.size(1);
    int HK = 4; // hardcoded in prompt / pa.cpp definition

    // Get kv_len from kv_indptr
    int kv_len = kv_indptr[1].item<int>();
    int part_num = (kv_len + KV_PART_SIZE - 1) / KV_PART_SIZE;

    dim3 grid(B, HK, part_num);
    dim3 block(256);

    hipLaunchKernelGGL(pa, grid, block, 0, 0,
        (__bf16*)query.data_ptr<at::BFloat16>(),
        (__bf16*)key_cache.data_ptr<at::BFloat16>(),
        (__bf16*)value_cache.data_ptr<at::BFloat16>(),
        (uint*)kv_indptr.data_ptr<int>(),
        (uint*)kv_page_indices.data_ptr<int>(),
        (__bf16*)out_seg.data_ptr<at::BFloat16>(),
        qk_ptr.data_ptr<float>(),
        max_out.data_ptr<float>(),
        sum_out.data_ptr<float>()
    );
}

void launch_pa_reduce(
    torch::Tensor kv_indptr,
    torch::Tensor out_seg,
    torch::Tensor max_out,
    torch::Tensor sum_out,
    torch::Tensor out,
    int max_part
) {
    int B = out.size(0);
    int HQ = out.size(1);

    dim3 grid(B, HQ);
    dim3 block(256);

    hipLaunchKernelGGL(pa_reduce, grid, block, 0, 0,
        (uint*)kv_indptr.data_ptr<int>(),
        (__bf16*)out_seg.data_ptr<at::BFloat16>(),
        max_out.data_ptr<float>(),
        sum_out.data_ptr<float>(),
        (__bf16*)out.data_ptr<at::BFloat16>(),
        (uint)max_part
    );
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("launch_pa", &launch_pa, "Launch pa kernel");
    m.def("launch_pa_reduce", &launch_pa_reduce, "Launch pa_reduce kernel");
}

